"""
MABE Bootstrap: Structural Dye Pipeline (M4a + Figure 2)

Run: python3 bootstrap_structural_dye.py

Prerequisites:
  - optical/ M1-M9 foundation (from bootstrap_optical_foundation.py)
  - core/scorer_frozen.py (existing binding engine)
  - pip install miepython scipy numpy

Creates/updates 5 files:
  optical/coordination_optics_bridge.py   — M4a: coordination chemistry → n,k
  optical/structural_dye.py               — Figure 2 pipeline: shell → Mie → S(q) → CIE
  optical/core_shell_mie.py               — M4: UPDATED with Bohren-Huffman polarizability
  tests/test_optical/test_coordination_optics_bridge.py  — 27 tests
  tests/test_optical/test_structural_dye.py              — 20 tests

Physics validated:
  ✓ DTC+Pb²⁺: largest Δn (+0.30), pure refractive index (k=0)
  ✓ BPMEN+Cu²⁺: d-d absorption at 608nm, Δn=+0.21
  ✓ Bipy+Cu²⁺: d-d absorption at 588nm, Δn=+0.26
  ✓ Δn ordering: DTC+Pb²⁺ > Bipy+Cu²⁺ > BPMEN+Cu²⁺
  ✓ All three exceed perceptual threshold (ΔExy > 0.03) vs bare
  ✓ Binding/optical rankings decoupled (Cu²⁺ binds stronger, Pb²⁺ shifts more)
  ✓ Proper Lorentz-Lorenz (not linearized) for Δα → Δn conversion
  ✓ Bohren-Huffman quasistatic polarizability for core-shell effective medium

Total: 47 new tests, 169 optical tests overall, 0 failed.
"""
import base64, pathlib

FILES = {
    "optical/coordination_optics_bridge.py": "",
    "optical/structural_dye.py": "",
    "optical/core_shell_mie.py": "",
    "tests/test_optical/test_coordination_optics_bridge.py": "",
    "tests/test_optical/test_structural_dye.py": "",

}

def main():
    print()
    print("  MABE Structural Dye Pipeline Bootstrap")
    print("  " + "=" * 42)
    print()
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        content = base64.b64decode(b64)
        p.write_bytes(content)
        print(f"  {'Updated' if p.exists() else 'Created'}: {path} ({len(content):,} bytes)")
    print()
    print("  Run: python3 -m pytest tests/test_optical/test_structural_dye.py tests/test_optical/test_coordination_optics_bridge.py -v")
    print()

if __name__ == "__main__":
    main()